import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { useAuth } from './AuthContext';

const WishlistContext = createContext();

export function useWishlist() {
  const ctx = useContext(WishlistContext);
  if (!ctx) throw new Error('useWishlist must be used within WishlistProvider');
  return ctx;
}

function unwrapWishlist(res) {
  const w = res?.data?.data?.wishlist;
  if (!w) return { products: [] };
  return w;
}

export function WishlistProvider({ children }) {
  const { user, loading: authLoading } = useAuth();
  const [wishlist, setWishlist] = useState({ products: [] });
  const [loading, setLoading] = useState(true);

  const fetchWishlist = useCallback(async () => {
    try {
      const res = await axios.get('/api/wishlist', { withCredentials: true });
      setWishlist(unwrapWishlist(res));
    } catch {
      setWishlist({ products: [] });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (authLoading) return;
    if (!user) {
      setWishlist({ products: [] });
      setLoading(false);
      return;
    }
    setLoading(true);
    fetchWishlist();
  }, [authLoading, user, fetchWishlist]);

  const toggleWishlist = async (productId) => {
    try {
      const res = await axios.post(
        `/api/wishlist/${encodeURIComponent(productId)}`,
        {},
        { withCredentials: true }
      );
      const d = res?.data?.data;
      if (d?.wishlist) setWishlist(d.wishlist);
      return { success: true, action: d?.action };
    } catch (error) {
      return {
        success: false,
        error:
          error.response?.data?.message || error.message || 'Wishlist update failed'
      };
    }
  };

  const count = wishlist.products?.length || 0;

  return (
    <WishlistContext.Provider
      value={{
        wishlist,
        products: wishlist.products || [],
        loading,
        count,
        fetchWishlist,
        toggleWishlist
      }}
    >
      {children}
    </WishlistContext.Provider>
  );
}
